ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/agriculture#>
PREFIX p: <http://ambrosia.example.org/agriculture/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  collective: { SELECT ?cropname ?yieldperacre WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasCrop ?child ; p:hasFarm ?parent . } GROUP BY ?child }
  ?child p:name ?cropname .
  ?child p:yieldPerAcre ?yieldperacre .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Farm } }
  FILTER(?nf = ?total)
} }
  distributive: { SELECT ?name ?cropname ?yieldperacre WHERE {
  ?farmscrops a :FarmsCrops .
  ?crops a :Crop .
  ?farmscrops p:hasCrop ?crops .
  ?farms a :Farm .
  ?farmscrops p:hasFarm ?farms .
  ?farms p:name ?name .
  ?crops p:name ?cropname .
  ?crops p:yieldPerAcre ?yieldperacre .
} }
}

